mapper.select:
SELECT id, account, password, name, type, status, create_time
FROM user
WHERE account = #{account}

SELECT id, account, password, name, type, status, create_time
FROM user
WHERE id = #{id}

SELECT id, account, name, type, status, create_time FROM user
AND name LIKE CONCAT('%', #{name}, '%')
AND type = #{type, typeHandler=com.text_to_sql.text_to_sql.handler.UserTypeHandler}
AND status = #{status, typeHandler=com.text_to_sql.text_to_sql.handler.UserStatusHandler}
ORDER BY status DESC, id ASC
